164	## 源码解析
165	
166	### Canvas.UpdateCanvasBatch
167	
168	Unity 2021.3 核心代码（简化版）：
169	
170	```csharp
171	// Canvas.cs
172	private void UpdateCanvasBatch()
173	{
174	    // 1. 收集所有可批次的Graphic
175	    var graphicList = ListPool<Graphic>.Get();
176	
177	    for (int i = 0; i < transform.childCount; i++)
178	    {
179	        var graphic = transform.GetChild(i).GetComponent<Graphic>();
180	        if (graphic != null && graphic.canvasRenderer.hasPopInstruction == false)
181	        {
182	            graphicList.Add(graphic);
183	        }
184	    }
185	
186	    // 2. 按材质和纹理排序
187	    graphicList.Sort((a, b) =>
188	    {
189	        // 优先按Material排序
190	        int materialCompare = CompareMaterial(a.material, b.material);
191	        if (materialCompare != 0)
192	            return materialCompare;
193	
194	        // 其次按Texture排序
195	        int textureCompare = CompareTexture(a.mainTexture, b.mainTexture);
196	        return textureCompare;
197	    });
198	
199	    // 3. 合批构建
200	    Material currentMaterial = null;
201	    Texture currentTexture = null;
202	
203	    foreach (var graphic in graphicList)
204	    {
205	        // 如果材质或纹理改变，开始新批次
206	        if (currentMaterial != graphic.material ||
207	            currentTexture != graphic.mainTexture)
208	        {
209	            // 结束当前批次
210	            FlushBatch();
211	
212	            // 开始新批次
213	            currentMaterial = graphic.material;
214	            currentTexture = graphic.mainTexture;
215	            BeginBatch(currentMaterial, currentTexture);
216	        }
217	
218	        // 添加到当前批次
219	        AddToBatch(graphic);
220	    }
221	
222	    // 4. 提交最后批次
223	    FlushBatch();
224	
225	    ListPool<Graphic>.Release(graphicList);
226	}
227	```
