229	### Graphic.Rebuild
230	
231	```csharp
232	// Graphic.cs
233	public virtual void Rebuild(CanvasUpdate update)
234	{
235	    if (update == CanvasUpdate.Prelayout)
236	    {
237	        // 布局前的准备
238	    }
239	    else if (update == CanvasUpdate.Layout)
240	    {
241	        // 重新计算布局
242	        LayoutRebuilder.MarkLayoutForRebuild(rectTransform);
243	    }
244	    else if (update == CanvasUpdate.PostLayout)
245	    {
246	        // 布局完成后的处理
247	    }
248	    else if (update == CanvasUpdate.PreRender)
249	    {
250	        // 重新生成顶点数据
251	        if (m_VertsDirty)
252	        {
253	            UpdateGeometry();
254	            m_VertsDirty = false;
255	        }
256	    }
257	}
