260	### CanvasUpdateRegistry
261	
262	```csharp
263	// CanvasUpdateRegistry.cs
264	public static class CanvasUpdateRegistry
265	{
266	    private static readonly List<ICanvasElement> s_LayoutRebuildQueue = new();
267	    private static readonly List<ICanvasElement> s_GraphicRebuildQueue = new();
268	
269	    public static void RegisterCanvasElementForLayoutRebuild(ICanvasElement element)
270	    {
271	        if (!s_LayoutRebuildQueue.Contains(element))
272	        {
273	            s_LayoutRebuildQueue.Add(element);
274	        }
275	    }
276	
277	    public static void RegisterCanvasElementForGraphicRebuild(ICanvasElement element)
278	    {
279	        if (!s_GraphicRebuildQueue.Contains(element))
280	        {
281	            s_GraphicRebuildQueue.Add(element);
282	        }
283	    }
284	
285	    public static void FullLayoutUpdate()
286	    {
287	        // 按顺序执行布局重建
288	        for (int i = 0; i < s_LayoutRebuildQueue.Count; i++)
289	        {
290	            s_LayoutRebuildQueue[i].Rebuild(CanvasUpdate.Layout);
291	        }
292	        s_LayoutRebuildQueue.Clear();
293	    }
294	
295	    public static void FullGraphicUpdate()
296	    {
297	        // 按顺序执行图形重建
298	        for (int i = 0; i < s_GraphicRebuildQueue.Count; i++)
299	        {
300	            s_GraphicRebuildQueue[i].Rebuild(CanvasUpdate.PreRender);
301	        }
302	        s_GraphicRebuildQueue.Clear();
303	    }
304	}
305	```
306	
307	### 合批决策树
308	
309	```
310	CanBatch(graphicA, graphicB)
311	│
312	├─> SameCanvas? ──NO──> ✗ 不能合批
313	│  └─> YES
314	│
315	├─> SameMaterial? ──NO──> ✗ 不能合批
316	│  └─> YES
317	│
318	├─> SameTexture? ──NO──> ✗ 不能合批
319	│  └─> YES
320	│
321	├─> SameClipping? ──NO──> ✗ 不能合批
322	│  └─> YES
323	│
324	├─> AdjacentInHierarchy? ──NO──> ✗ 不能合批
325	│  └─> YES
326	│
327	└─> ✓ 可以合批
328	```
