443	## 实战案例
444	
445	### 案例1: 滚动列表优化
446	
447	**问题：** 100个Item的ScrollList，滚动时帧率掉到30FPS
448	
449	**诊断：**
450	```
451	1. 每个Item独立Canvas → DrawCall爆炸（100+）
452	2. Text每帧Graphic Rebuild → CPU瓶颈
453	3. 非可视区域也在渲染 → 浪费GPU
454	```
455	
456	**解决方案：**
457	
458	```csharp
459	// 1. 使用ObjectPool
460	public class ScrollListPool : MonoBehaviour
461	{
462	    [SerializeField] private GameObject itemPrefab;
463	    [SerializeField] private RectTransform content;
464	    [SerializeField] private int poolSize = 20;
465	
466	    private ObjectPool<GameObject> pool;
467	    private List<GameObject> activeItems = new();
468	
469	    private void Awake()
470	    {
471	        pool = new ObjectPool<GameObject>(
472	            createFunc: () => Instantiate(itemPrefab, content),
473	            actionOnGet: (item) => item.SetActive(true),
474	            actionOnRelease: (item) => item.SetActive(false),
475	            maxSize: poolSize
476	        );
477	    }
478	
479	    public void SetItems(List<ItemData> items)
480	    {
481	        // 清空当前显示
482	        foreach (var item in activeItems)
483	        {
484	            pool.Release(item);
485	        }
486	        activeItems.Clear();
487	
488	        // 创建新Item
489	        foreach (var data in items)
490	        {
491	            var item = pool.Get();
492	            item.GetComponent<ItemView>().SetData(data);
493	            activeItems.Add(item);
494	        }
495	    }
496	}
497	
498	// 2. 可视区域剔除
499	public class ScrollListCulling : MonoBehaviour
500	{
501	    [SerializeField] private RectTransform viewport;
502	    [SerializeField] private RectTransform content;
503	
504	    private void Update()
505	    {
506	        float viewportTop = viewport.rect.height / 2;
507	        float viewportBottom = -viewport.rect.height / 2;
508	
509	        foreach (Transform child in content)
510	        {
511	            var itemRect = (RectTransform)child;
512	            Vector2 localPos = content.InverseTransformPoint(itemRect.position);
513	
514	            // 只渲染可视区域的Item
515	            itemRect.gameObject.SetActive(
516	                localPos.y < viewportTop && localPos.y > viewportBottom
517	            );
518	        }
519	    }
520	}
521	
522	// 3. 减少Text Rebuild
523	public class OptimizedText : MonoBehaviour
524	{
525	    private TextMeshProUGUI textComponent;
526	    private string lastText;
527	
528	    private void Awake()
529	    {
530	        textComponent = GetComponent<TextMeshProUGUI>();
531	    }
532	
533	    public void SetText(string newText)
534	    {
535	        // 只在内容改变时更新
536	        if (newText != lastText)
537	        {
538	            textComponent.text = newText;
539	            lastText = newText;
540	
541	            // 强制立即重建，避免异步重建
542	            textComponent.ForceMeshUpdate();
543	        }
544	    }
545	}
546	```
547	
548	**优化效果：**
549	- DrawCall: 100+ → 5
550	- Frame Time: 33ms → 8ms
551	- FPS: 30 → 120+
