708	**解决方案：**
709	```csharp
710	// 正确做法1：使用MaterialPropertyBlock
711	public class OptimizedColorChanger : MonoBehaviour
712	{
713	    private MaterialPropertyBlock propBlock;
714	    private Image image;
715	
716	    private void Awake()
717	    {
718	        image = GetComponent<Image>();
719	        propBlock = new MaterialPropertyBlock();
720	    }
721	
722	    public void UpdateColor(Color color)
723	    {
724	        image.material.GetPropertyBlock(propBlock);
725	        propBlock.SetColor("_Color", color);
726	        image.material.SetPropertyBlock(propBlock);
727	    }
728	}
729	
730	// 正确做法2：使用DOTween缓存
731	image.DOColor(targetColor, duration);
732	// DOTween会智能更新，不会每帧触发Rebuild
733	```
