842	
843	**现象：** 动态修改Canvas sortingOrder导致卡顿
844	
845	**根因：** Sorting Order改变会触发整个渲染队列重组
846	
847	**解决方案：**
848	```csharp
849	// 错误做法
850	canvas.sortingOrder = ++counter;
851	
852	// 正确做法：使用父子层级控制深度
853	public class DepthManager : MonoBehaviour
854	{
855	    private Transform[] depthLayers;
856	
857	    public void SetDepth(Transform uiObject, int depth)
858	    {
859	        // 通过父子关系控制深度，避免修改sortingOrder
860	        if (depth >= 0 && depth < depthLayers.Length)
861	        {
862	            uiObject.SetParent(depthLayers[depth], false);
863	        }
864	    }
865	
866	    private void InitializeDepthLayers()
867	    {
868	        depthLayers = new Transform[10];
869	        for (int i = 0; i < depthLayers.Length; i++)
870	        {
871	            var layer = new GameObject($"Depth_{i}").transform;
872	            layer.SetParent(transform, false);
873	            depthLayers[i] = layer;
874	        }
875	    }
876	}
877	```
