256	### 解决方案
257	
258	```csharp
259	// ✅ 方案1: 减少LayoutGroup使用
260	public class ReducedLayoutGroup : MonoBehaviour
261	{
262	    [SerializeField] private GameObject itemPrefab;
263	
264	    private void Start()
265	    {
266	        for (int i = 0; i < 100; i++)
267	        {
268	            var item = Instantiate(itemPrefab, transform);
269	
270	            // 不使用嵌套的LayoutGroup
271	            // 直接设置anchoredPosition
272	            item.GetComponent<RectTransform>().anchoredPosition =
273	                new Vector2(0, -i * 50);
274	        }
275	    }
276	}
277	
278	// ✅ 方案2: 手动布局替代LayoutGroup
279	public class ManualLayout : MonoBehaviour
280	{
281	    [SerializeField] private GameObject itemPrefab;
282	    [SerializeField] private float itemHeight = 50f;
283	    [SerializeField] private float spacing = 10f;
284	
285	    private List<RectTransform> items = new();
286	
287	    public void AddItem()
288	    {
289	        var item = Instantiate(itemPrefab, transform).GetComponent<RectTransform>();
290	        item.anchoredPosition = new Vector2(0, -items.Count * (itemHeight + spacing));
291	        items.Add(item);
292	    }
293	
294	    public void RemoveItem(int index)
295	    {
296	        if (index >= 0 && index < items.Count)
297	        {
298	            var item = items[index];
299	            items.RemoveAt(index);
300	            Destroy(item.gameObject);
301	
302	            // 重新布局
303	            RefreshLayout();
304	        }
305	    }
306	
307	    private void RefreshLayout()
308	    {
309	        for (int i = 0; i < items.Count; i++)
310	        {
311	            items[i].anchoredPosition = new Vector2(0, -i * (itemHeight + spacing));
312	        }
313	    }
314	}
