316	// ✅ 方案3: 使用ContentSizeFitter替代LayoutGroup
317	public class ContentSizeFitterLayout : MonoBehaviour
318	{
319	    [SerializeField] private GameObject itemPrefab;
320	    [SerializeField] private RectTransform content;
321	    [SerializeField] private ContentSizeFitter fitter;
322	
323	    private bool needsLayout = false;
324	
325	    public void AddItem()
326	    {
327	        Instantiate(itemPrefab, content);
328	        needsLayout = true;
329	    }
330	
331	    private void LateUpdate()
332	    {
333	        // 延迟布局，避免每帧Rebuild
334	        if (needsLayout)
335	        {
336	            LayoutRebuilder.ForceRebuildLayoutImmediate(content);
337	            needsLayout = false;
338	        }
339	    }
