342	// ✅ 方案4: 虚拟列表
343	public class VirtualLayoutList : MonoBehaviour
344	{
345	    [SerializeField] private GameObject itemPrefab;
346	    [SerializeField] private RectTransform content;
347	    [SerializeField] private RectTransform viewport;
348	    [SerializeField] private float itemHeight = 50f;
349	
350	    private int itemCount = 100;
351	    private int startIndex = 0;
352	    private List<RectTransform> visibleItems = new();
353	
354	    private void UpdateVisibleItems()
355	    {
356	        float viewportHeight = viewport.rect.height;
357	        int visibleCount = Mathf.CeilToInt(viewportHeight / itemHeight) + 2;
358	
359	        // 计算起始索引
360	        float scrollPos = -content.anchoredPosition.y;
361	        startIndex = Mathf.Max(0, Mathf.FloorToInt(scrollPos / itemHeight));
362	
363	        // 调整可见项数量
364	        while (visibleItems.Count < visibleCount)
365	        {
366	            var item = Instantiate(itemPrefab, content).GetComponent<RectTransform>();
367	            visibleItems.Add(item);
368	        }
369	
370	        // 更新位置
371	        for (int i = 0; i < visibleItems.Count; i++)
372	        {
373	            int itemIndex = startIndex + i;
374	            if (itemIndex < itemCount)
375	            {
376	                visibleItems[i].anchoredPosition = new Vector2(0, -itemIndex * itemHeight);
377	                visibleItems[i].gameObject.SetActive(true);
378	            }
379	            else
380	            {
381	                visibleItems[i].gameObject.SetActive(false);
382	            }
383	        }
384	    }
385	}
