473	#### Unity内部机制
474	
475	```csharp
476	// Graphic.cs (简化版)
477	public abstract class Graphic : UIBehaviour, ICanvasElement
478	{
479	    private bool m_VertsDirty;
480	    private bool m_MaterialDirty;
481	    private bool m_LayoutDirty;
482	
483	    public Color color
484	    {
485	        get { return m_Color; }
486	        set
487	        {
488	            if (m_Color != value)
489	            {
490	                m_Color = value;
491	                SetVerticesDirty();  // 触发Vertex Rebuild
492	                SetMaterialDirty();  // 触发Material Rebuild
493	            }
494	        }
495	    }
496	
497	    public Sprite sprite
498	    {
499	        get { return m_Sprite; }
500	        set
501	        {
502	            if (m_Sprite != value)
503	            {
504	                m_Sprite = value;
505	                SetAllDirty();  // 触发所有Rebuild
506	            }
507	        }
508	    }
509	
510	    public float fillAmount
511	    {
512	        get { return m_FillAmount; }
513	        set
514	        {
515	            if (m_FillAmount != value)
516	            {
517	                m_FillAmount = value;
518	                SetVerticesDirty();  // 触发Vertex Rebuild
519	            }
520	        }
521	    }
522	
523	    protected void SetVerticesDirty()
524	    {
525	        if (!m_VertsDirty)
526	        {
527	            m_VertsDirty = true;
528	            CanvasUpdateRegistry.RegisterCanvasElementForGraphicRebuild(this);
529	        }
530	    }
531	
532	    protected void SetMaterialDirty()
533	    {
534	        if (!m_MaterialDirty)
535	        {
536	            m_MaterialDirty = true;
537	            CanvasUpdateRegistry.RegisterCanvasElementForGraphicRebuild(this);
538	        }
539	    }
540	
541	    public virtual void Rebuild(CanvasUpdate update)
542	    {
543	        if (update == CanvasUpdate.PreRender)
544	        {
545	            if (m_VertsDirty)
546	            {
547	                UpdateGeometry();
548	                m_VertsDirty = false;
549	            }
550	
551	            if (m_MaterialDirty)
552	            {
553	                UpdateMaterial();
554	                m_MaterialDirty = false;
555	            }
556	        }
557	    }
558	
559	    protected virtual void UpdateGeometry()
560	    {
561	        // 重新生成Mesh（耗时操作）
562	    }
563	}
564	```
