1098	    {
1099	        // 按材质分组
1100	        var images = elements.OfType<Image>().ToList();
1101	        var texts = elements.OfType<Text>().ToList();
1102	
1103	        // Image在前，Text在后
1104	        int index = 0;
1105	        foreach (var image in images)
1106	        {
1107	            image.SetSiblingIndex(index++);
1108	        }
1109	        foreach (var text in texts)
1110	        {
1111	            text.SetSiblingIndex(index++);
1112	        }
1113	    }
1114	}
