190	#### 解决方案
191	
192	```csharp
193	// 创建自定义字体图集
194	public class CustomFontAtlasCreator : MonoBehaviour
195	{
196	    [MenuItem("Tools/Create Optimized Font")]
197	    public static void CreateOptimizedFont()
198	    {
199	        // 1. 选择源字体文件
200	        string fontPath = "Assets/Fonts/MyFont.ttf";
201	
202	        // 2. 创建字体配置
203	        var fontAsset = TMP_FontAsset.CreateFontAsset(
204	            fontPath,
205	            90,                    // Atlas Size
206	            90,                    // Face Size
207	            32,                    // Padding
208	            3,                     // Atlas Padding
209	            true,                  // Multi-channel
210	            GlyphRenderMode.SDFAA, // Render Mode
211	            32,                    // Atlas Width
212	            32,                    // Atlas Height
213	            new int[] { 0x20, 0x7E, 0x4E00, 0x9FFF } // ASCII + 中文常用字符
214	        );
215	
216	        // 3. 配置图集
217	        fontAsset.atlasResolution = 1024;  // 限制图集大小
218	
219	        // 4. 保存资源
220	        AssetDatabase.CreateAsset(fontAsset, "Assets/Fonts/MyFont_SDF.asset");
221	        AssetDatabase.Refresh();
