227	// 动态字体加载优化
228	public class DynamicFontLoader : MonoBehaviour
229	{
230	    [SerializeField] private TMP_FontAsset[] fontAssets;
231	    private Dictionary<string, TMP_FontAsset> fontCache = new();
232	
233	    private void Awake()
234	    {
235	        // 预加载字体
236	        foreach (var font in fontAssets)
237	        {
238	            if (font != null)
239	            {
240	                fontCache[font.name] = font;
241	                font.LoadFontAtlas();  // 预加载图集
242	            }
243	        }
244	    }
245	
246	    public TMP_FontAsset GetFont(string fontName)
247	    {
248	        return fontCache.TryGetValue(fontName, out var font) ? font : null;
249	    }
250	}
