283	```csharp
284	// 方案1: 对象池
285	public class TextMeshProPool : MonoBehaviour
286	{
287	    [SerializeField] private TextMeshProUGUI prefab;
288	    private Queue<TextMeshProUGUI> pool = new();
289	
290	    public TextMeshProUGUI GetText()
291	    {
292	        if (pool.Count > 0)
293	        {
294	            return pool.Dequeue();
295	        }
296	        return Instantiate(prefab, transform);
297	    }
298	
299	    public void ReturnText(TextMeshProUGUI text)
300	    {
301	        text.SetText("");  // 清空但不销毁
302	        text.gameObject.SetActive(false);
303	        pool.Enqueue(text);
304	    }
305	}
