588	// 方案4: 预分配字符数组
589	public class PreAllocatedText : MonoBehaviour
590	{
591	    [SerializeField] private TextMeshProUGUI statusText;
592	    private char[] charBuffer = new char[256];
593	
594	    public void UpdateStatus(int score, float time)
595	    {
596	        // 手动格式化到缓冲区
597	        int length = 0;
598	
599	        // 写入"Score: "
600	        char[] scorePrefix = "Score: ".ToCharArray();
601	        Array.Copy(scorePrefix, 0, charBuffer, length, scorePrefix.Length);
602	        length += scorePrefix.Length;
603	
604	        // 写入数值
605	        int scoreLength = FormatInt(score, charBuffer, length);
606	        length += scoreLength;
607	
608	        // 写入" | Time: "
609	        char[] timePrefix = " | Time: ".ToCharArray();
610	        Array.Copy(timePrefix, 0, charBuffer, length, timePrefix.Length);
611	        length += timePrefix.Length;
612	
613	        // 写入时间
614	        int timeLength = FormatFloat(time, charBuffer, length, 2);
615	        length += timeLength;
616	
617	        // 设置文本
618	        statusText.SetText(charBuffer, 0, length);
619	    }
620	
621	    private int FormatInt(int value, char[] buffer, int offset)
622	    {
623	        int length = 0;
624	        if (value < 0)
625	        {
626	            buffer[offset++] = '-';
627	            value = -value;
628	        }
629	
630	        int start = offset;
631	        do
632	        {
633	            buffer[offset++] = (char)('0' + (value % 10));
634	            value /= 10;
635	        } while (value > 0);
636	
637	        length = offset - start;
638	
639	        // 反转字符
640	        for (int i = 0; i < length / 2; i++)
641	        {
642	            char temp = buffer[start + i];
643	            buffer[start + i] = buffer[start + length - i - 1];
644	            buffer[start + length - i - 1] = temp;
645	        }
646	
647	        return length;
648	    }
649	
650	    private int FormatFloat(float value, char[] buffer, int offset, int decimalPlaces)
651	    {
652	        // 简化实现，实际可以使用更高效的算法
653	        string str = value.ToString($"F{decimalPlaces}");
654	        for (int i = 0; i < str.Length; i++)
655	        {
656	            buffer[offset + i] = str[i];
657	        }
658	        return str.Length;
659	    }
660	}
