728	// 方案2: 虚拟列表（可视区域渲染）
729	public class VirtualTextList : MonoBehaviour
730	{
731	    [SerializeField] private TextMeshProUGUI textPrefab;
732	    [SerializeField] private RectTransform content;
733	    [SerializeField] private RectTransform viewport;
734	    [SerializeField] private float itemHeight = 40f;
735	
736	    private List<TextMeshProUGUI> visibleItems = new();
737	    private List<string> allItems = new();
738	    private int startIndex = 0;
739	
740	    public void SetItems(List<string> items)
741	    {
742	        allItems = items;
743	        UpdateVisibleItems();
744	    }
745	
746	    private void UpdateVisibleItems()
747	    {
748	        // 计算可视区域
749	        float viewportHeight = viewport.rect.height;
750	        int visibleCount = Mathf.CeilToInt(viewportHeight / itemHeight) + 2;
751	
752	        // 计算起始索引
753	        float scrollPos = -content.anchoredPosition.y;
754	        startIndex = Mathf.Max(0, Mathf.FloorToInt(scrollPos / itemHeight));
755	
756	        // 调整可见项数量
757	        while (visibleItems.Count < visibleCount && startIndex + visibleItems.Count < allItems.Count)
758	        {
759	            var item = Instantiate(textPrefab, content);
760	            item.rectTransform.anchoredPosition = new Vector2(0, (startIndex + visibleItems.Count) * -itemHeight);
761	            item.rectTransform.sizeDelta = new Vector2(content.rect.width, itemHeight);
762	            visibleItems.Add(item);
763	        }
764	
765	        // 更新文本
766	        for (int i = 0; i < visibleItems.Count; i++)
767	        {
768	            int itemIndex = startIndex + i;
769	            if (itemIndex < allItems.Count)
770	            {
771	                visibleItems[i].SetText(allItems[itemIndex]);
772	                visibleItems[i].gameObject.SetActive(true);
773	            }
774	            else
775	            {
776	                visibleItems[i].gameObject.SetActive(false);
777	            }
778	        }
779	    }
780	
781	    public void OnScroll(Vector2 delta)
782	    {
783	        content.anchoredPosition += new Vector2(0, delta.y);
784	        UpdateVisibleItems();
785	    }
786	}
