788	// 方案3: 对象池 + 虚拟列表
789	public class PooledVirtualList : MonoBehaviour
790	{
791	    [SerializeField] private TextMeshProUGUI itemPrefab;
792	    [SerializeField] private RectTransform content;
793	    [SerializeField] private RectTransform viewport;
794	    [SerializeField] private float itemHeight = 40f;
795	    [SerializeField] private int poolSize = 20;
796	
797	    private ObjectPool<TextMeshProUGUI> pool;
798	    private List<TextMeshProUGUI> activeItems = new();
799	    private List<string> allItems = new();
800	    private int startIndex = 0;
801	
802	    private void Awake()
803	    {
804	        pool = new ObjectPool<TextMeshProUGUI>(
805	            createFunc: () => Instantiate(itemPrefab, content),
806	            actionOnGet: (item) => item.gameObject.SetActive(true),
807	            actionOnRelease: (item) => item.gameObject.SetActive(false),
808	            maxSize: poolSize
809	        );
810	    }
811	
812	    public void SetItems(List<string> items)
813	    {
814	        // 释放所有活跃项
815	        foreach (var item in activeItems)
816	        {
817	            pool.Release(item);
818	        }
819	        activeItems.Clear();
820	
821	        allItems = items;
822	        UpdateVisibleItems();
823	    }
824	
825	    private void UpdateVisibleItems()
826	    {
827	        float viewportHeight = viewport.rect.height;
828	        int visibleCount = Mathf.CeilToInt(viewportHeight / itemHeight) + 2;
829	
830	        float scrollPos = -content.anchoredPosition.y;
831	        startIndex = Mathf.Max(0, Mathf.FloorToInt(scrollPos / itemHeight));
832	
833	        // 获取或创建可见项
834	        while (activeItems.Count < visibleCount && startIndex + activeItems.Count < allItems.Count)
835	        {
836	            var item = pool.Get();
837	            item.rectTransform.anchoredPosition = new Vector2(0, (startIndex + activeItems.Count) * -itemHeight);
838	            item.rectTransform.sizeDelta = new Vector2(content.rect.width, itemHeight);
839	            activeItems.Add(item);
840	        }
841	
842	        // 更新文本
843	        for (int i = 0; i < activeItems.Count; i++)
844	        {
845	            int itemIndex = startIndex + i;
846	            if (itemIndex < allItems.Count)
847	            {
848	                activeItems[i].SetText(allItems[itemIndex]);
849	            }
850	            else
851	            {
852	                pool.Release(activeItems[i]);
853	                activeItems.RemoveAt(i);
854	                i--;
855	            }
856	        }
857	    }
858	
859	    public void OnScroll(Vector2 delta)
860	    {
861	        content.anchoredPosition += new Vector2(0, delta.y);
862	        UpdateVisibleItems();
863	    }
864	}
