985	        msgObj.SetText(formatted);
986	
987	        // 添加到队列
988	        messageQueue.Enqueue(formatted);
989	
990	        // 限制数量
991	        if (messageQueue.Count > maxMessages)
992	        {
993	            messageQueue.Dequeue();
994	            // 释放最旧的消息
995	            var oldest = msgObj.transform.parent.GetChild(0).GetComponent<TextMeshProUGUI>();
996	            messagePool.Release(oldest);
997	        }
998	
999	        // 重新布局
1000	        LayoutRebuilder.MarkLayoutForRebuild(chatText.transform.parent as RectTransform);
1001	    }
1002	}
1003	```
