90	### 1.3 UI DrawCall优化
91	
92	```csharp
93	using UnityEngine;
94	using UnityEngine.UI;
95	
96	/// <summary>
97	/// UI DrawCall优化器
98	/// </summary>
99	public class UIDrawCallOptimizer : MonoBehaviour
100	{
101	    /*
102	    ========== UI合批规则 ==========
103	
104	    1. 相同材质/图集
105	    2. 相同层级（Canvas下）
106	    3. 没有被其他元素打断
107	    4. 正确的渲染顺序
108	
109	    ========== 打断合批的常见原因 ==========
110	
111	    1. 不同图集的Image交叉排列
112	    2. Text组件穿插在Image之间
113	    3. 使用了Mask组件
114	    4. 不同材质的UI元素
115	    5. 激活/禁用组件改变层级
116	    */
117	
118	    /// <summary>
119	    /// 分析Canvas的DrawCall情况
120	    /// </summary>
121	    public static void AnalyzeCanvas(Canvas canvas)
122	    {
123	        var graphics = canvas.GetComponentsInChildren<Graphic>(true);
124	
125	        System.Collections.Generic.Dictionary<string, int> atlasCount =
126	            new System.Collections.Generic.Dictionary<string, int>();
127	
128	        foreach (var graphic in graphics)
129	        {
130	            if (graphic is Image image && image.sprite != null)
131	            {
132	                string atlasName = image.sprite.texture?.name ?? "None";
133	                if (!atlasCount.ContainsKey(atlasName))
134	                    atlasCount[atlasName] = 0;
135	                atlasCount[atlasName]++;
136	            }
137	            else if (graphic is Text text)
138	            {
139	                string fontName = text.font?.name ?? "None";
140	                if (!atlasCount.ContainsKey($"Font:{fontName}"))
141	                    atlasCount[$"Font:{fontName}"] = 0;
142	                atlasCount[$"Font:{fontName}"]++;
143	            }
144	        }
145	
146	        Debug.Log($"===== Canvas Analysis: {canvas.name} =====");
147	        Debug.Log($"Total Graphics: {graphics.Length}");
148	        Debug.Log($"Potential Atlases/Fonts: {atlasCount.Count}");
149	
150	        foreach (var kvp in atlasCount)
151	        {
152	            Debug.Log($"  {kvp.Key}: {kvp.Value} elements");
153	        }
154	    }
155	
156	    /// <summary>
157	    /// 重新排序UI元素以优化合批
158	    /// </summary>
159	    public static void ReorderForBatching(RectTransform parent)
160	    {
161	        var children = new System.Collections.Generic.List<RectTransform>();
162	        foreach (Transform child in parent)
163	        {
164	            children.Add(child as RectTransform);
165	        }
166	
167	        // 按材质/图集分组排序
168	        children.Sort((a, b) =>
169	        {
170	            var graphicA = a.GetComponent<Graphic>();
171	            var graphicB = b.GetComponent<Graphic>();
172	
173	            string keyA = GetSortingKey(graphicA);
174	            string keyB = GetSortingKey(graphicB);
175	
176	            return string.Compare(keyA, keyB, System.StringComparison.Ordinal);
177	        });
178	
179	        // 重新设置兄弟索引
180	        for (int i = 0; i < children.Count; i++)
181	        {
182	            children[i].SetSiblingIndex(i);
183	        }
184	    }
185	
186	    private static string GetSortingKey(Graphic graphic)
187	    {
188	        if (graphic is Image image && image.sprite != null)
189	        {
190	            return image.sprite.texture?.name ?? "Image_None";
191	        }
192	        if (graphic is Text text)
193	        {
194	            return $"Text_{text.font?.name ?? "None"}";
195	        }
196	        return graphic.GetType().Name;
197	    }
198	}
