261	    /// 预加载图集
262	    /// </summary>
263	    public void PreloadAtlas(string atlasName)
264	    {
265	        if (atlasDict.TryGetValue(atlasName, out var atlas))
266	        {
267	            // 强制加载所有Sprite
268	            Sprite[] sprites = new Sprite[atlas.spriteCount];
269	            atlas.GetSprites(sprites);
270	
271	            foreach (var sprite in sprites)
272	            {
273	                string cacheKey = $"{atlasName}_{sprite.name}";
274	                if (!spriteCache.ContainsKey(cacheKey))
275	                {
276	                    spriteCache[cacheKey] = sprite;
277	                }
278	            }
279	        }
280	    }
281	
282	    /// <summary>
283	    /// 清理Sprite缓存
284	    /// </summary>
285	    public void ClearCache()
286	    {
287	        spriteCache.Clear();
288	    }
289	}
